import React from 'react';
import AcompanhamentoRelatorioEconomico from '../components/AcompanhamentoRelatorioEconomico';
import MenuLateral from '../components/MenuLateral';
import { useLocation } from 'react-router-dom';

const PaginaAcompanhamentoRelatorioEconomico = () => {
  const location = useLocation();
  const params = new URLSearchParams(location.search);
  const razaoSocial = params.get('razaoSocial') || '';
  const cnpj = params.get('cnpj') || '';
  return (
    <div style={{display:'flex'}}>
      <MenuLateral
        clienteInfo={razaoSocial && cnpj ? (
          <>
            <div style={{fontWeight:700, fontSize: '1.1rem', color: '#fff'}}>{razaoSocial}</div>
            <div style={{fontWeight:500, fontSize: '0.95rem', color: '#fff'}}>CNPJ: {cnpj}</div>
          </>
        ) : null}
      />
      <div style={{marginLeft:200, flex:1, minHeight:'100vh', background:'#f8f9fb', padding:'2rem'}}>
        <div style={{marginTop:'40px'}}>
          <AcompanhamentoRelatorioEconomico razaoSocial={razaoSocial} />
        </div>
      </div>
    </div>
  );
};

export default PaginaAcompanhamentoRelatorioEconomico;
